import React, { useState, useEffect } from 'react';
import CourseCard from '../components/CourseCard';
import config, { getAllCourses } from '../config/config';
import { getRecentMaterials } from '../services/api';
import { 
  getFeaturedCourses, 
  getStats, 
  checkHealth,
  addSampleCourses 
} from '../services/api';
import { useNavigate } from 'react-router-dom';
import './Home.css';

const Home = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [backendCourses, setBackendCourses] = useState([]);
  const [loading, setLoading] = useState(true);
  const [backendStatus, setBackendStatus] = useState('checking');
  const [windowWidth, setWindowWidth] = useState(window.innerWidth);
  
  const [stats, setStats] = useState([
    { title: 'Total Notes', value: 'Loading...', icon: '📄', key: 'notes' },
    { title: 'PYQs', value: 'Loading...', icon: '📝', key: 'pyqs' },
    { title: 'Courses', value: 'Loading...', icon: '🎓', key: 'courses' },
    { title: 'Downloads', value: 'Loading...', icon: '⬇️', key: 'downloads' },
  ]);
  const [showAddCoursesBtn, setShowAddCoursesBtn] = useState(false);
  
  // ✅ NEW STATE FOR MATERIALS
  const [latestMaterials, setLatestMaterials] = useState([]);
  const [materialsLoading, setMaterialsLoading] = useState(true);
  const [materialsError, setMaterialsError] = useState('');
  
  const navigate = useNavigate();
  
  // Get courses from config (static/hardcoded)
  const staticCourses = getAllCourses();

  // Handle window resize
  useEffect(() => {
    const handleResize = () => {
      setWindowWidth(window.innerWidth);
    };

    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  useEffect(() => {
    // Check backend connection first
    checkBackend();
    fetchData();
    
    // ✅ YAHAN API CALL FOR MATERIALS
    fetchLatestMaterials();
  }, []);

  // ✅ NEW FUNCTION: FETCH MATERIALS FROM BACKEND
  // ✅ FIXED: fetchLatestMaterials function
const fetchLatestMaterials = async () => {
  try {
    setMaterialsLoading(true);
    setMaterialsError('');
    
    console.log('Fetching materials from: http://localhost:5000/api/materials');
    
    const response = await fetch('http://localhost:5000/api/materials');
    const data = await response.json();
    
    console.log('Materials API Response:', data);
    
    if (data.success) {
      // Transform data to ensure course_name is present
      const transformedMaterials = data.materials.map(m => ({
        ...m,
        course_name: m.course || m.course_name || 'Unknown',  // ✅ FIX: course_name
        display_course: m.course || m.course_name || 'Unknown'
      }));
      
      setLatestMaterials(transformedMaterials.slice(0, 6));
    } else {
      setMaterialsError(data.error || 'Failed to fetch materials');
    }
  } catch (error) {
    console.error('Materials fetch error:', error);
    setMaterialsError('Connection failed. Check if backend is running on port 5000');
  } finally {
    setMaterialsLoading(false);
  }
};

// ✅ FIXED DOWNLOAD FUNCTION FOR LATEST MATERIALS
const handleMaterialClick = async (material) => {
  console.log('📥 Downloading material:', material.id);
  
  try {
    // Get token from localStorage
    const token = localStorage.getItem('study_portal_token');
    
    // Check if user is logged in
    if (!token) {
      const shouldLogin = window.confirm('Please login first to download materials. Go to login page?');
      if (shouldLogin) {
        navigate('/login');
      }
      return;
    }
    
    // Show downloading status
    const downloadBtn = document.getElementById(`download-${material.id}`);
    if (downloadBtn) {
      downloadBtn.textContent = '⏳ Downloading...';
      downloadBtn.disabled = true;
    }
    
    // CORRECT DOWNLOAD URL
    const downloadUrl = `http://localhost:5000/api/notes/${material.id}/download`;
    console.log('🔗 Download URL:', downloadUrl);
    
    // Make fetch request with token
    const response = await fetch(downloadUrl, {
      method: 'GET',
      headers: {
        'Authorization': `Bearer ${token}`,
        'Content-Type': 'application/json',
      }
    });
    
    console.log('📊 Response status:', response.status);
    
    if (!response.ok) {
      if (response.status === 401) {
        throw new Error('Session expired. Please login again.');
      } else if (response.status === 404) {
        throw new Error('File not found on server');
      } else {
        throw new Error(`Download failed (${response.status})`);
      }
    }
    
    // Get the blob from response
    const blob = await response.blob();
    console.log('📦 Blob size:', blob.size, 'type:', blob.type);
    
    // Get filename from Content-Disposition header or use default
    const contentDisposition = response.headers.get('Content-Disposition');
    let filename = material.file_name || `${material.title}.pdf`;
    
    if (contentDisposition) {
      const match = contentDisposition.match(/filename[^;=\n]*=((['"]).*?\2|[^;\n]*)/);
      if (match && match[1]) {
        filename = match[1].replace(/['"]/g, '');
      }
    }
    
    // Create download link
    const url = window.URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = filename;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    window.URL.revokeObjectURL(url);
    
    alert('✅ Download started!');
    
  } catch (error) {
    console.error('❌ Download error:', error);
    
    // Show specific error message
    if (error.message.includes('401')) {
      alert('⚠️ Session expired. Please login again.');
      localStorage.removeItem('study_portal_token');
      navigate('/login');
    } else if (error.message.includes('404')) {
      alert('❌ File not found on server. It may have been deleted.');
    } else {
      alert(`❌ Download failed: ${error.message}`);
    }
  } finally {
    // Reset button
    const downloadBtn = document.getElementById(`download-${material.id}`);
    if (downloadBtn) {
      downloadBtn.textContent = 'Download';
      downloadBtn.disabled = false;
    }
  }
};

  const checkBackend = async () => {
    try {
      const health = await checkHealth();
      setBackendStatus('connected');
      console.log('✅ Backend connected:', health);
      
      // Show add courses button if no courses in DB
      if (health.course_count === 0) {
        setShowAddCoursesBtn(true);
      }
    } catch (error) {
      setBackendStatus('disconnected');
      console.error('❌ Backend connection failed:', error);
    }
  };

  const handleAddSampleCourses = async () => {
    try {
      setLoading(true);
      const result = await addSampleCourses();
      alert(`✅ ${result.message}`);
      setShowAddCoursesBtn(false);
      fetchData(); // Refresh courses
    } catch (error) {
      alert('❌ Failed to add sample courses');
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const fetchData = async () => {
    try {
      // Fetch courses from backend
      const coursesData = await getFeaturedCourses(6);
      
      // Transform backend data to match CourseCard expectations
      const transformedCourses = coursesData.courses.map(course => ({
        id: course.id,
        name: course.name,
        branch: course.branch || 'General',
        semester: course.semester || 'All',
        code: course.code || 'GEN',
        notes: course.notes || 0,
        pyqs: course.pyqs || 0,
        description: course.description || 'Study materials',
        created_at: course.created_at
      }));
      
      setBackendCourses(transformedCourses);
      
      // Fetch stats
      const statsData = await getStats();
      setStats([
        { 
          title: 'Total Notes', 
          value: `${statsData.totalNotes || config.STATS_DEFAULTS.totalNotes}+`, 
          icon: '📄',
          key: 'notes'
        },
        { 
          title: 'PYQs', 
          value: `${statsData.totalPYQs || config.STATS_DEFAULTS.totalPYQs}+`, 
          icon: '📝',
          key: 'pyqs'
        },
        { 
          title: 'Courses', 
          value: `${statsData.totalCourses || config.STATS_DEFAULTS.totalCourses}+`, 
          icon: '🎓',
          key: 'courses'
        },
        { 
          title: 'Downloads', 
          value: `${statsData.totalDownloads || config.STATS_DEFAULTS.totalDownloads}+`, 
          icon: '⬇️',
          key: 'downloads'
        },
      ]);
      
    } catch (error) {
      console.error('Error fetching data:', error);
      
      // Use static courses if backend fails
      setBackendCourses([]);
      
      // Set default stats
      setStats([
        { 
          title: 'Total Notes', 
          value: `${config.STATS_DEFAULTS.totalNotes}+`, 
          icon: '📄',
          key: 'notes'
        },
        { 
          title: 'PYQs', 
          value: `${config.STATS_DEFAULTS.totalPYQs}+`, 
          icon: '📝',
          key: 'pyqs'
        },
        { 
          title: 'Courses', 
          value: `${config.STATS_DEFAULTS.totalCourses}+`, 
          icon: '🎓',
          key: 'courses'
        },
        { 
          title: 'Downloads', 
          value: `${config.STATS_DEFAULTS.totalDownloads}+`, 
          icon: '⬇️',
          key: 'downloads'
        },
      ]);
      
      setBackendStatus('disconnected');
    } finally {
      setLoading(false);
    }
  };

  const handleSearch = async () => {
    if (searchQuery.trim()) {
      navigate(`/search?q=${encodeURIComponent(searchQuery)}`);
      setSearchQuery(''); // Optional: clear input
    }
  };

  const handleCourseClick = (courseId) => {
    navigate(`/course/${courseId}`);
  };

  // ✅ NEW FUNCTION: Handle material click

  // Decide which courses to display
  const displayCourses = backendStatus === 'connected' && backendCourses.length > 0 
    ? backendCourses 
    : staticCourses.map(course => ({
        id: course.id,
        name: course.name,
        branch: course.branches?.[0] || 'General',
        semester: 'All',
        code: course.name.substring(0, 4).toUpperCase(),
        notes: config.STATS_DEFAULTS.totalNotes / 5,
        pyqs: config.STATS_DEFAULTS.totalPYQs / 5,
        description: course.description,
        icon: course.icon,
        color: course.color,
        duration: course.duration
      }));

  const features = [
    { title: 'Updated Content', desc: 'Regularly updated materials', icon: '✅' },
    { title: 'Easy Search', desc: 'Find materials quickly', icon: '🔍' },
    { title: 'Mobile Friendly', desc: 'Access on any device', icon: '📱' },
    { title: 'Free Forever', desc: 'All resources free', icon: '🆓' },
  ];

  // Base styles (immutable)
  const baseStyles = {
    container: {
      minHeight: '100vh',
      background: 'linear-gradient(135deg, #f8fafc 0%, #e2e8f0 100%)',
      paddingBottom: '2rem'
    },
    heroSection: {
      textAlign: 'center',
      padding: '4rem 1rem',
      background: 'linear-gradient(90deg, #4f46e5 0%, #7c3aed 100%)',
      color: 'white',
      borderRadius: '0 0 20px 20px',
      marginBottom: '2rem',
      position: 'relative'
    },
    statusBadge: {
      position: 'absolute',
      top: '10px',
      right: '10px',
      padding: '5px 15px',
      borderRadius: '20px',
      fontSize: '0.9rem',
      fontWeight: 'bold',
      background: backendStatus === 'connected' ? '#10b981' : '#ef4444',
      display: 'flex',
      alignItems: 'center',
      gap: '5px'
    },
    heroTitle: {
      fontSize: windowWidth < 768 ? '2rem' : '2.5rem',
      fontWeight: 'bold',
      marginBottom: '1rem',
    },
    heroSubtitle: {
      fontSize: windowWidth < 768 ? '1rem' : '1.1rem',
      opacity: 0.9,
      marginBottom: '2rem',
      maxWidth: '600px',
      margin: '0 auto 2rem',
      padding: '0 1rem'
    },
    searchContainer: {
      maxWidth: '600px',
      margin: '0 auto',
      display: 'flex',
      gap: '10px',
      padding: '0 1rem'
    },
    searchInput: {
      flex: 1,
      padding: '1rem 1.5rem',
      borderRadius: '25px',
      border: 'none',
      fontSize: '1rem',
      boxShadow: '0 4px 6px rgba(0,0,0,0.1)',
      outline: 'none'
    },
    searchButton: {
      padding: windowWidth < 768 ? '0 1.5rem' : '0 2rem',
      borderRadius: '25px',
      border: 'none',
      background: '#10b981',
      color: 'white',
      fontWeight: 'bold',
      fontSize: '1rem',
      cursor: 'pointer',
      transition: 'all 0.3s',
      '&:hover': {
        background: '#059669',
        transform: 'scale(1.05)'
      }
    },
    addCoursesBtn: {
      marginTop: '1rem',
      padding: '0.75rem 1.5rem',
      background: '#f59e0b',
      color: 'white',
      border: 'none',
      borderRadius: '25px',
      fontWeight: 'bold',
      cursor: 'pointer',
      transition: 'all 0.3s',
      '&:hover': {
        background: '#d97706'
      }
    },
    statsSection: {
      maxWidth: '1200px',
      margin: '0 auto 3rem',
      padding: '0 1rem'
    },
    statCard: {
      background: 'white',
      padding: '1.5rem',
      borderRadius: '10px',
      textAlign: 'center',
      boxShadow: '0 4px 6px rgba(0,0,0,0.1)',
      transition: 'transform 0.3s, box-shadow 0.3s',
      '&:hover': {
        transform: 'translateY(-5px)',
        boxShadow: '0 10px 25px rgba(0,0,0,0.1)'
      }
    },
    statIcon: {
      fontSize: '2.5rem',
      marginBottom: '0.5rem'
    },
    statNumber: {
      fontSize: windowWidth < 768 ? '1.5rem' : '2rem',
      fontWeight: 'bold',
      color: '#4f46e5',
      marginBottom: '0.25rem'
    },
    statLabel: {
      color: '#6b7280',
      fontSize: '0.9rem'
    },
    coursesSection: {
      maxWidth: '1200px',
      margin: '0 auto 3rem',
      padding: '0 1rem'
    },
    sectionTitle: {
      fontSize: windowWidth < 768 ? '1.75rem' : '2rem',
      textAlign: 'center',
      marginBottom: '2rem',
      color: '#1f2937'
    },
    viewAll: {
      textAlign: 'center',
      marginTop: '2rem'
    },
    viewAllBtn: {
      padding: '0.75rem 2rem',
      background: 'linear-gradient(90deg, #4f46e5, #7c3aed)',
      color: 'white',
      border: 'none',
      borderRadius: '25px',
      fontWeight: 'bold',
      fontSize: '1rem',
      cursor: 'pointer',
      transition: 'all 0.3s',
      '&:hover': {
        transform: 'scale(1.05)',
        boxShadow: '0 5px 15px rgba(79, 70, 229, 0.4)'
      }
    },
    featuresSection: {
      maxWidth: '1200px',
      margin: '0 auto 3rem',
      padding: '0 1rem'
    },
    featureCard: {
      background: 'white',
      padding: '1.5rem',
      borderRadius: '10px',
      textAlign: 'center',
      boxShadow: '0 4px 6px rgba(0,0,0,0.1)',
      transition: 'transform 0.3s',
      '&:hover': {
        transform: 'translateY(-3px)'
      }
    },
    featureIcon: {
      fontSize: '2.5rem',
      marginBottom: '1rem'
    },
    loading: {
      textAlign: 'center',
      padding: '3rem',
      color: '#6b7280',
      fontSize: '1.1rem'
    },
    error: {
      textAlign: 'center',
      padding: '2rem',
      color: '#ef4444',
      background: '#fee2e2',
      borderRadius: '10px',
      margin: '2rem'
    },
    connectionInfo: {
      textAlign: 'center',
      marginTop: '1rem',
      fontSize: '0.9rem',
      color: 'rgba(255,255,255,0.8)'
    },
    courseItem: {
      cursor: 'pointer',
      transition: 'transform 0.3s',
      '&:hover': {
        transform: 'translateY(-5px)'
      }
    },
    // ✅ NEW STYLES FOR MATERIALS SECTION
    materialsSection: {
      maxWidth: '1200px',
      margin: '0 auto 3rem',
      padding: '0 1rem',
      background: 'white',
      borderRadius: '15px',
      boxShadow: '0 10px 30px rgba(0,0,0,0.1)',
      paddingTop: '2rem',
      paddingBottom: '2rem'
    },
    materialCard: {
      background: '#f8fafc',
      padding: '1.5rem',
      borderRadius: '10px',
      border: '1px solid #e2e8f0',
      transition: 'all 0.3s',
      cursor: 'pointer',
      '&:hover': {
        background: '#f1f5f9',
        transform: 'translateY(-3px)',
        boxShadow: '0 8px 20px rgba(0,0,0,0.1)'
      }
    },
    materialTypeBadge: {
      display: 'inline-block',
      padding: '0.25rem 0.75rem',
      borderRadius: '15px',
      fontSize: '0.75rem',
      fontWeight: 'bold',
      marginBottom: '0.5rem'
    },
    materialTitle: {
      fontSize: '1.1rem',
      fontWeight: '600',
      color: '#1f2937',
      marginBottom: '0.5rem'
    },
    materialMeta: {
      color: '#6b7280',
      fontSize: '0.875rem',
      marginBottom: '0.25rem'
    },
    materialDownloadBtn: {
      marginTop: '0.75rem',
      padding: '0.5rem 1rem',
      background: '#4f46e5',
      color: 'white',
      border: 'none',
      borderRadius: '5px',
      fontSize: '0.875rem',
      fontWeight: '500',
      cursor: 'pointer',
      transition: 'all 0.2s',
      '&:hover': {
        background: '#4338ca'
      }
    }
  };

  // Responsive grid styles based on window width
  const getResponsiveGridStyles = () => {
    if (windowWidth >= 1024) {
      return {
        statsGrid: { gridTemplateColumns: 'repeat(4, 1fr)' },
        coursesGrid: { gridTemplateColumns: 'repeat(3, 1fr)' },
        featuresGrid: { gridTemplateColumns: 'repeat(4, 1fr)' },
        materialsGrid: { gridTemplateColumns: 'repeat(3, 1fr)' } // ✅ NEW
      };
    } else if (windowWidth >= 768) {
      return {
        statsGrid: { gridTemplateColumns: 'repeat(4, 1fr)' },
        coursesGrid: { gridTemplateColumns: 'repeat(2, 1fr)' },
        featuresGrid: { gridTemplateColumns: 'repeat(2, 1fr)' },
        materialsGrid: { gridTemplateColumns: 'repeat(2, 1fr)' } // ✅ NEW
      };
    } else {
      return {
        statsGrid: { gridTemplateColumns: 'repeat(2, 1fr)' },
        coursesGrid: { gridTemplateColumns: 'repeat(1, 1fr)' },
        featuresGrid: { gridTemplateColumns: 'repeat(1, 1fr)' },
        materialsGrid: { gridTemplateColumns: 'repeat(1, 1fr)' } // ✅ NEW
      };
    }
  };

  const responsiveStyles = getResponsiveGridStyles();

  // ✅ Function to get badge color based on material type
  const getMaterialTypeColor = (type) => {
    switch (type) {
      case 'notes': return { background: '#dbeafe', color: '#1d4ed8' };
      case 'pyq': return { background: '#fef3c7', color: '#d97706' };
      case 'syllabus': return { background: '#dcfce7', color: '#15803d' };
      case 'imp_questions': return { background: '#f3e8ff', color: '#7c3aed' };
      default: return { background: '#f1f5f9', color: '#64748b' };
    }
  };

  return (
    <div style={baseStyles.container}>
      {/* Hero Section */}
      <section style={baseStyles.heroSection}>
        <div style={baseStyles.statusBadge}>
          {backendStatus === 'connected' ? '✅ Connected' : '❌ Disconnected'}
          <span style={{ fontSize: '0.8rem', marginLeft: '5px' }}>
            {backendStatus === 'connected' ? 'http://localhost:5000' : 'Offline'}
          </span>
        </div>
        
        <h1 style={baseStyles.heroTitle}>Welcome to {config.APP_NAME}</h1>
        <p style={baseStyles.heroSubtitle}>
          Your one-stop destination for notes, PYQs, syllabus and study materials
        </p>
        
        <div style={baseStyles.searchContainer}>
          <input
            type="text"
            placeholder="Search courses, notes, PYQs..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && handleSearch()}
            style={baseStyles.searchInput}
          />
          <button 
            onClick={handleSearch}
            style={baseStyles.searchButton}
          >
            🔍 Search
          </button>
        </div>

        {showAddCoursesBtn && backendStatus === 'connected' && (
          <button 
            onClick={handleAddSampleCourses}
            style={baseStyles.addCoursesBtn}
            disabled={loading}
          >
            {loading ? 'Adding...' : '➕ Add Sample Courses to Database'}
          </button>
        )}

        <div style={baseStyles.connectionInfo}>
          Backend: http://localhost:5000 | 
          Database: {backendStatus === 'connected' ? 'Connected' : 'Using Static Data'} | 
          Courses: {displayCourses.length}
        </div>
      </section>

      {/* Stats Section */}
      <section style={baseStyles.statsSection}>
        <div style={{
          display: 'grid',
          gap: '1rem',
          ...responsiveStyles.statsGrid
        }}>
          {stats.map((stat, index) => (
            <div key={index} style={baseStyles.statCard}>
              <div style={baseStyles.statIcon}>{stat.icon}</div>
              <h3 style={baseStyles.statNumber}>{stat.value}</h3>
              <p style={baseStyles.statLabel}>{stat.title}</p>
            </div>
          ))}
        </div>
      </section>

      {/* Featured Courses */}
      <section style={baseStyles.coursesSection}>
        <h2 style={baseStyles.sectionTitle}>Select Your Course</h2>
        
        {loading ? (
          <div style={baseStyles.loading}>
            <div style={{ fontSize: '2rem', marginBottom: '1rem' }}>⏳</div>
            <p>Loading courses...</p>
            <p>Backend Status: <strong>{backendStatus}</strong></p>
          </div>
        ) : displayCourses.length === 0 && backendStatus === 'connected' ? (
          <div style={baseStyles.error}>
            <div style={{ fontSize: '2rem', marginBottom: '1rem' }}>📭</div>
            <h3>No courses found in database!</h3>
            <p>Click the "Add Sample Courses" button above to populate the database.</p>
            <button 
              onClick={handleAddSampleCourses}
              style={{...baseStyles.viewAllBtn, background: '#f59e0b', marginTop: '1rem'}}
              disabled={loading}
            >
              {loading ? 'Adding...' : '➕ Add Sample Courses'}
            </button>
          </div>
        ) : (
          <>
            <div style={{
              display: 'grid',
              gap: '1.5rem',
              ...responsiveStyles.coursesGrid
            }}>
              {displayCourses.map(course => (
                <div 
                  key={course.id} 
                  style={baseStyles.courseItem}
                  onClick={() => handleCourseClick(course.id)}
                >
                  <CourseCard 
                    course={{
                      ...course,
                      onCourseClick: () => handleCourseClick(course.id)
                    }}
                  />
                </div>
              ))}
            </div>
            
            <div style={baseStyles.viewAll}>
              <p style={{ color: '#6b7280', marginBottom: '1rem' }}>
                Click on any course card to select and view years
              </p>
            </div>
          </>
        )}
      </section>

      {/* ✅ NEW: Latest Materials Section */}
      <section style={baseStyles.materialsSection}>
        <h2 style={baseStyles.sectionTitle}>📚 Latest Study Materials</h2>
        
        {materialsLoading ? (
          <div style={baseStyles.loading}>
            <div style={{ fontSize: '2rem', marginBottom: '1rem' }}>⏳</div>
            <p>Loading latest materials from backend...</p>
          </div>
        ) : materialsError ? (
          <div style={baseStyles.error}>
            <div style={{ fontSize: '2rem', marginBottom: '1rem' }}>❌</div>
            <h3>Failed to load materials</h3>
            <p>{materialsError}</p>
            <p style={{ fontSize: '0.9rem', marginTop: '0.5rem' }}>
              Make sure backend is running: <code>python app.py</code>
            </p>
          </div>
        ) : latestMaterials.length === 0 ? (
          <div style={{
            textAlign: 'center',
            padding: '3rem',
            background: '#f8fafc',
            borderRadius: '10px'
          }}>
            <div style={{ fontSize: '2rem', marginBottom: '1rem' }}>📭</div>
            <h3>No materials found</h3>
            <p>Upload some materials to see them here</p>
          </div>
        ) : (
          <>
            <div style={{
              display: 'grid',
              gap: '1.5rem',
              ...responsiveStyles.materialsGrid
            }}>
              {latestMaterials.map((material) => {
                const typeColor = getMaterialTypeColor(material.material_type || material.note_type);
                
                return (
                  <div 
                    key={material.id} 
                    style={baseStyles.materialCard}
                    onClick={() => handleMaterialClick(material)}
                  >
                    <div style={{
                      ...baseStyles.materialTypeBadge,
                      background: typeColor.background,
                      color: typeColor.color
                    }}>
                      {(material.material_type || material.note_type || 'notes').toUpperCase()}
                    </div>
                    
                    <h4 style={baseStyles.materialTitle}>
                      {material.title}
                    </h4>
                    
                    <p style={baseStyles.materialMeta}>
                      <strong>Course:</strong> {material.course_name || 'N/A'}
                    </p>
                    
                    <p style={baseStyles.materialMeta}>
                      <strong>Uploaded by:</strong> {material.user_name || 'Unknown'}
                    </p>
                    
                    <p style={baseStyles.materialMeta}>
                      <strong>Date:</strong> {new Date(material.uploaded_at).toLocaleDateString()}
                    </p>
                    
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: '1rem' }}>
                      <span style={{ fontSize: '0.875rem', color: '#6b7280' }}>
                        👁️ {material.views || 0} | ⬇️ {material.downloads || 0}
                      </span>
                      
                      <button 
                        style={baseStyles.materialDownloadBtn}
                        onClick={(e) => {
                          e.stopPropagation();
                          handleMaterialClick(material);
                        }}
                      >
                        Download
                      </button>
                    </div>
                  </div>
                );
              })}
            </div>
            
            <div style={baseStyles.viewAll}>
              <button 
                onClick={() => navigate('/all-materials')}
                style={baseStyles.viewAllBtn}
              >
                View All Materials →
              </button>
            </div>
          </>
        )}
      </section>

      {/* Features Section */}
      <section style={baseStyles.featuresSection}>
        <h2 style={baseStyles.sectionTitle}>Why Choose {config.APP_NAME}?</h2>
        <div style={{
          display: 'grid',
          gap: '1.5rem',
          ...responsiveStyles.featuresGrid
        }}>
          {features.map((feature, index) => (
            <div key={index} style={baseStyles.featureCard}>
              <div style={baseStyles.featureIcon}>{feature.icon}</div>
              <h3 style={{ marginBottom: '0.5rem', color: '#1f2937' }}>{feature.title}</h3>
              <p style={{ color: '#6b7280', lineHeight: '1.5' }}>{feature.desc}</p>
            </div>
          ))}
        </div>
      </section>

      {/* Backend Info */}
      <div style={{
        textAlign: 'center',
        marginTop: '3rem',
        padding: '1rem',
        color: '#6b7280',
        fontSize: '0.9rem'
      }}>
        <p>
          <strong>Backend Status:</strong> {backendStatus} | 
          <strong> Courses Loaded:</strong> {displayCourses.length} | 
          <strong> Latest Materials:</strong> {latestMaterials.length} |
          <strong> Mode:</strong> {backendStatus === 'connected' ? 'Live API' : 'Static Demo'}
        </p>
        <p style={{ fontSize: '0.8rem', marginTop: '0.5rem' }}>
          {backendStatus === 'connected' ? '✅ Frontend-Backend Connection Successful!' : '⚠️ Using static demo data'}
        </p>
      </div>
    </div>
  );
};

export default Home;
